def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = ratio ** 3
        elif ratio > 1:
            score = ratio * 15
        else:
            for j in range(1, 10):
                term = ((-1) ** (j+1)) * (ratio ** j) / (j * (j+1))
                if j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.8
                score += term
            if capacity < item * 1.5:
                score *= 2
            elif capacity < item * 3:
                score *= 1.2
            else:
                score *= 0.5
            if ratio < 0.3:
                score -= 0.1
        if capacity % 2 == 0:
            score += (capacity % 5) * 0.05
        else:
            score -= (capacity % 3) * 0.03
        priorities[i] = score if score > 0 else -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 200
    return priorities
